  dim_utility=EXCLUDED.dim_utility, dim_author_rep=EXCLUDED.dim_author_rep;

INSERT INTO memory_nodes
  (id,schema_version,workspace_id,title,content_type,content_format,body,
   tags,visibility,author,created_at,signature,source_type,
   trust_score,dim_accuracy,dim_freshness,dim_utility,dim_author_rep,
   votes_up,votes_down,verifications,traversal_count,unique_traverser_count)
VALUES
  ('mem_a004','1.0','ws_spec0001','對話式問答（Conversational Q&A）','procedural','plain','viewer 以上角色可對知識庫進行自然語言問答。Q&A 為唯讀操作，不修改知識庫內容。

執行流程：
1. 使用者傳送訊息
2. search_nodes(query) → 取得最相關的 5 個節點
3. traverse(最高分節點, depth=1) → 補充鄰近上下文（可選）
4. 組合 prompt：system 說明（只使用提供的節點作答，並引用節點 ID）+ 節點內容 + 使用者問題
5. 呼叫 AI（使用工作區 AI provider 設定，§16.5）
6. 回傳：answer + cited_nodes[] + tokens_used + session_id

API：
- POST /workspaces/{ws_id}/chat — 發送訊息（傳入 session_id 可延續對話，不傳則建立新 session）
- GET /workspaces/{ws_id}/chat/sessions — 列出使用者的 session 清單
- GET /workspaces/{ws_id}/chat/sessions/{session_id} — 取得完整對話紀錄

多輪對話：session 中最近 10 則訊息會一起送入 context window 以支援連續問答。

Schema：chat_sessions（id, workspace_id, user_id, created_at, updated_at）和 chat_messages（id, session_id, role user/assistant, content, cited_nodes[], tokens_used, created_at）。

注意：即使是 public 工作區，Q&A 也需要登入。未認證使用者無法使用此功能。',
   ARRAY['ai', 'chat', 'q&a', 'conversational', 'session', 'read-only']::text[],'public','system','2026-04-12T00:00:00+00:00','f3a4b5c6d7e8f3a4b5c6d7e8f3a4b5c6d7e8f3a4b5c6d7e8f3a4b5c6d7e8f3a4','human',
   0.95,0.95,1.0,0.95,0.9,
